import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

/**
 * Merge class names with Tailwind-aware conflict resolution.
 * The standard shadcn/ui `cn` helper.
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2",
        sm: "h-8 rounded-md px-3 text-xs",
        lg: "h-10 rounded-md px-6",
        icon: "size-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp
        ref={ref}
        className={cn(buttonVariants({ variant, size, className }))}
        {...props}
      />
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";
import { Copy, RotateCcw, Square, Paperclip } from "lucide-react";

import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";

export type MessageRole = "user" | "assistant" | "system";

export interface MessageAttachment {
  id?: string;
  name: string;
  /** Size in bytes, rendered human-readable if provided. */
  size?: number;
  type?: string;
}

const ROLE_LABEL: Record<MessageRole, string> = {
  user: "You",
  assistant: "Assistant",
  system: "System",
};

function formatBytes(bytes?: number): string | undefined {
  if (bytes == null) return undefined;
  if (bytes < 1024) return `${bytes} B`;
  const kb = bytes / 1024;
  if (kb < 1024) return `${Math.round(kb)} KB`;
  return `${(kb / 1024).toFixed(1)} MB`;
}

export interface MessageProps
  extends Omit<React.HTMLAttributes<HTMLElement>, "content"> {
  role: MessageRole;
  /** Author label. Defaults to a role-based label ("You" / "Assistant"). */
  name?: React.ReactNode;
  /** Whether an assistant message is currently streaming in. */
  streaming?: boolean;
  /** Attachments to display with the message. */
  attachments?: MessageAttachment[];
  /** Stop generation (shown while `streaming`). */
  onStop?: () => void;
  /** Regenerate (shown when an assistant message is complete). */
  onRegenerate?: () => void;
  /** Copy the message. */
  onCopy?: () => void;
  children?: React.ReactNode;
}

/**
 * `<Message>` — an accessible chat message with first-class streaming.
 *
 * The body is an ARIA live region (`aria-live="polite"`, `aria-busy` while
 * streaming) so screen readers hear assistant output as it arrives. A
 * reduced-motion-aware caret signals streaming; stop / regenerate / copy are
 * real, labelled buttons. Author and streaming state are exposed to assistive
 * tech, not just shown visually.
 */
export const Message = React.forwardRef<HTMLElement, MessageProps>(
  function Message(
    {
      role,
      name,
      streaming = false,
      attachments,
      onStop,
      onRegenerate,
      onCopy,
      children,
      className,
      ...rest
    },
    ref,
  ) {
    const label = name ?? ROLE_LABEL[role];
    const isAssistant = role === "assistant";

    return (
      <article
        ref={ref}
        data-felt="message"
        data-role={role}
        data-streaming={streaming || undefined}
        className={cn("flex flex-col gap-1.5", className)}
        {...rest}
      >
        <div className="flex items-center gap-2 text-xs font-medium text-muted-foreground">
          <span>{label}</span>
          {isAssistant ? (
            <span className="sr-only" role="status" aria-live="polite">
              {streaming ? `${label} is responding.` : ""}
            </span>
          ) : null}
        </div>

        <div
          // Live region: assistant output is announced as it streams in.
          aria-live={isAssistant ? "polite" : undefined}
          aria-atomic={isAssistant ? false : undefined}
          aria-busy={streaming || undefined}
          className={cn(
            "w-fit max-w-[40rem] rounded-lg px-3.5 py-2.5 text-sm leading-relaxed",
            role === "user" && "bg-primary text-primary-foreground",
            role === "assistant" && "bg-muted text-foreground",
            role === "system" &&
              "border border-dashed border-border bg-transparent text-muted-foreground",
          )}
        >
          {children}
          {streaming ? (
            <span
              aria-hidden="true"
              className="ml-0.5 inline-block h-[1em] w-[2px] translate-y-[0.15em] animate-pulse bg-current align-baseline motion-reduce:animate-none"
            />
          ) : null}
        </div>

        {attachments && attachments.length > 0 ? (
          <ul
            aria-label="Attachments"
            className="flex flex-wrap gap-1.5"
          >
            {attachments.map((file, i) => {
              const size = formatBytes(file.size);
              return (
                <li
                  key={file.id ?? i}
                  className="inline-flex items-center gap-1.5 rounded-md border border-border bg-card px-2 py-1 text-xs text-card-foreground"
                >
                  <Paperclip
                    className="size-3 shrink-0 text-muted-foreground"
                    aria-hidden="true"
                  />
                  <span className="max-w-[12rem] truncate">{file.name}</span>
                  {size ? (
                    <span className="text-muted-foreground">{size}</span>
                  ) : null}
                </li>
              );
            })}
          </ul>
        ) : null}

        {/* Per-message actions. */}
        {onStop || onRegenerate || onCopy ? (
          <div className="flex flex-wrap gap-1">
            {streaming && onStop ? (
              <Button size="sm" variant="ghost" onClick={onStop}>
                <Square />
                Stop
              </Button>
            ) : null}
            {!streaming && onRegenerate ? (
              <Button size="sm" variant="ghost" onClick={onRegenerate}>
                <RotateCcw />
                Regenerate
              </Button>
            ) : null}
            {!streaming && onCopy ? (
              <Button size="sm" variant="ghost" onClick={onCopy}>
                <Copy />
                Copy
              </Button>
            ) : null}
          </div>
        ) : null}
      </article>
    );
  },
);

import * as React from "react";
import { ArrowUp, Paperclip, Square, X } from "lucide-react";

import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import type { MessageAttachment } from "./message";

export interface ComposerProps
  extends Omit<
    React.FormHTMLAttributes<HTMLFormElement>,
    "onSubmit" | "onChange"
  > {
  /** Controlled value. Omit for uncontrolled use. */
  value?: string;
  defaultValue?: string;
  onValueChange?: (value: string) => void;
  /** Called with the trimmed text on submit (Enter or the send button). */
  onSubmit?: (value: string) => void;
  placeholder?: string;
  /** Accessible label for the textarea. Default "Message". */
  label?: string;
  disabled?: boolean;
  /**
   * When true, the send button becomes a Stop button (calls `onStop`) — the
   * assistant is generating.
   */
  streaming?: boolean;
  onStop?: () => void;
  /** Show the attach button + wire it to a hidden file input. */
  onAttach?: (files: FileList) => void;
  /** Current attachments, rendered as removable chips. */
  attachments?: MessageAttachment[];
  onRemoveAttachment?: (attachment: MessageAttachment, index: number) => void;
  sendLabel?: string;
}

/**
 * `<Composer>` — an accessible message input.
 *
 * Enter submits, Shift+Enter inserts a newline. While `streaming`, the send
 * affordance becomes a labelled Stop button. Attachments are real list items
 * with remove buttons, and the hidden file input is driven by a labelled
 * trigger. Controlled or uncontrolled.
 */
export const Composer = React.forwardRef<HTMLFormElement, ComposerProps>(
  function Composer(
    {
      value,
      defaultValue = "",
      onValueChange,
      onSubmit,
      placeholder = "Send a message…",
      label = "Message",
      disabled = false,
      streaming = false,
      onStop,
      onAttach,
      attachments,
      onRemoveAttachment,
      sendLabel = "Send",
      className,
      ...rest
    },
    ref,
  ) {
    const isControlled = value !== undefined;
    const [internal, setInternal] = React.useState(defaultValue);
    const text = isControlled ? value : internal;
    const fileInputRef = React.useRef<HTMLInputElement>(null);

    const setText = React.useCallback(
      (next: string) => {
        if (!isControlled) setInternal(next);
        onValueChange?.(next);
      },
      [isControlled, onValueChange],
    );

    const hasAttachments = !!attachments && attachments.length > 0;
    const canSend = (text.trim().length > 0 || hasAttachments) && !disabled;

    const submit = React.useCallback(() => {
      if (!canSend) return;
      onSubmit?.(text.trim());
      if (!isControlled) setInternal("");
    }, [canSend, onSubmit, text, isControlled]);

    const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === "Enter" && !e.shiftKey && !e.nativeEvent.isComposing) {
        e.preventDefault();
        submit();
      }
    };

    return (
      <form
        ref={ref}
        data-felt="composer"
        onSubmit={(e) => {
          e.preventDefault();
          submit();
        }}
        className={cn(
          "flex flex-col gap-2 rounded-xl border border-input bg-background p-2 shadow-sm focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-2 focus-within:ring-offset-background",
          className,
        )}
        {...rest}
      >
        {hasAttachments ? (
          <ul
            aria-label="Attachments"
            className="flex flex-wrap gap-1.5 px-1 pt-1"
          >
            {attachments!.map((file, i) => (
              <li
                key={file.id ?? i}
                className="inline-flex items-center gap-1.5 rounded-md border border-border bg-muted px-2 py-1 text-xs"
              >
                <Paperclip
                  className="size-3 shrink-0 text-muted-foreground"
                  aria-hidden="true"
                />
                <span className="max-w-[12rem] truncate">{file.name}</span>
                {onRemoveAttachment ? (
                  <button
                    type="button"
                    onClick={() => onRemoveAttachment(file, i)}
                    aria-label={`Remove ${file.name}`}
                    className="rounded-sm text-muted-foreground hover:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                  >
                    <X className="size-3" aria-hidden="true" />
                  </button>
                ) : null}
              </li>
            ))}
          </ul>
        ) : null}

        <textarea
          aria-label={label}
          rows={1}
          value={text}
          disabled={disabled}
          placeholder={placeholder}
          onChange={(e) => setText(e.target.value)}
          onKeyDown={handleKeyDown}
          className="max-h-48 min-h-[2.5rem] w-full resize-none bg-transparent px-2 py-1.5 text-sm leading-relaxed outline-none placeholder:text-muted-foreground disabled:opacity-50"
        />

        <div className="flex items-center justify-between gap-2">
          {onAttach ? (
            <>
              <input
                ref={fileInputRef}
                type="file"
                multiple
                className="sr-only"
                tabIndex={-1}
                aria-hidden="true"
                onChange={(e) => {
                  if (e.target.files?.length) onAttach(e.target.files);
                  e.target.value = "";
                }}
              />
              <Button
                type="button"
                size="icon"
                variant="ghost"
                disabled={disabled}
                aria-label="Attach files"
                onClick={() => fileInputRef.current?.click()}
              >
                <Paperclip />
              </Button>
            </>
          ) : (
            <span />
          )}

          {streaming ? (
            <Button
              type="button"
              size="icon"
              variant="secondary"
              onClick={onStop}
              aria-label="Stop generating"
            >
              <Square />
            </Button>
          ) : (
            <Button
              type="submit"
              size="icon"
              disabled={!canSend}
              aria-label={sendLabel}
            >
              <ArrowUp />
            </Button>
          )}
        </div>
      </form>
    );
  },
);
